def read_csv(path: Path) -> list[dict]:
    with path.open() as f:
        return list(csv.DictReader(f))

def write_csv(rows: list[dict], path: Path):
    if not rows:
        return
    with path.open('w', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=rows[0].keys())
        writer.writeheader()
        writer.writerows(rows)

@cli.command()
@click.argument('input_path', type=click.Path(exists=True, path_type=Path))
@click.option('--column', '-c', required=True)
@click.option('--value', '-v', required=True)
@click.option('-o', '--output', type=click.Path(path_type=Path), default=Path('output.csv'))
def filter(input_path, column, value, output):
    rows = read_csv(input_path)
    filtered = [r for r in rows if r.get(column) == value]
    write_csv(filtered, output)
    click.echo(f'Filtered to {len(filtered)} rows')
