@cli.command()
@click.argument('left', type=click.Path(exists=True, path_type=Path))
@click.argument('right', type=click.Path(exists=True, path_type=Path))
@click.option('--key', '-k', required=True, help='Column to join on')
@click.option('-o', '--output', type=click.Path(path_type=Path), default=Path('merged.csv'))
def merge(left, right, key, output):
    left_rows = read_csv(left)
    right_rows = read_csv(right)
    right_lookup = {r[key]: r for r in right_rows}
    merged = []
    for lr in left_rows:
        rr = right_lookup.get(lr.get(key))
        if rr:
            merged.append({**lr, **rr})
    write_csv(merged, output)
    console.print(f'Merged {len(merged)} rows')
